module adder_32bit (
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:0] carry;

assign carry[0] = 1'b0;
assign C32 = carry[32];

genvar i;
    for (i = 1; i < 32; i = i + 1) begin
        end // Auto-repaired
        assign {carry[i], S[i]} = A[i] + B[i] + carry[i-1];
    end

assign {carry[32], S[32]} = A[32] + B[32] + carry[31];

endmodule
